        public static string[,] RetrieveData(string levelName, int layerNumber)
        {
            switch (levelName)
            {
                case "WM1":
                    if (WM1.Count < layerNumber)
                    {
                        Log.Error("Layer does not exist.");
                        return null;
                    }
                    else
                    {
                        return WM1.ElementAt(layerNumber);
                    }
                case "TS1":
                    if (TS1.Count < layerNumber)
                    {
